import path from "node:path";
import { nanoid } from "nanoid";
import { db, type DocumentRow, initDb } from "../db/index.ts";
import { convertPdfToMarkdown } from "../pdf/convert.ts";
import { UPLOADS_DIR } from "../config.ts";
import { generatePlan } from "../agent/plan.ts";
import { generateQuiz } from "../agent/quiz.ts";
import {
  generateRetryHint,
  explainCorrect,
  learnMore,
} from "../agent/feedback.ts";
import { generateSummary, type AttemptInput } from "../agent/summary.ts";
import type {
  QuizQuestionRow,
  LessonPlanRow,
  AttemptRow,
} from "../db/index.ts";

initDb();

export interface Objective {
  text: string;
  topic: string;
}
export interface QuizDTO {
  id: number;
  objectiveIndex: number;
  objectiveText: string;
  question: string;
  options: string[];
  hint: string;
}
export interface AttemptSummaryDTO {
  score: number;
  total: number;
  summary: string;
  studyTips: string[];
  weakTopics: string[];
  strengths: string[];
  answers: Array<{
    question: string;
    options: string[];
    correctIndex: number;
    learnerIndex: number | null;
    attempts: number;
    objectiveText: string;
  }>;
}

export async function listDocuments() {
  const rows = db
    .prepare(
      `SELECT id, filename, title, markdown_chars, status, error, created_at
       FROM documents ORDER BY datetime(created_at) DESC`,
    )
    .all() as Array<
    Pick<
      DocumentRow,
      | "id"
      | "filename"
      | "title"
      | "markdown_chars"
      | "status"
      | "error"
      | "created_at"
    >
  >;
  return rows.map((r) => {
    const planRow = db
      .prepare(
        `SELECT id, difficulty, status FROM lesson_plans WHERE document_id = ? ORDER BY datetime(created_at) DESC LIMIT 1`,
      )
      .get(r.id) as
      | { id: number; difficulty: string; status: string }
      | undefined;
    const attemptCount = (
      db
        .prepare(
          `SELECT COUNT(*) AS c FROM attempts a JOIN lesson_plans p ON p.id = a.lesson_plan_id WHERE p.document_id = ?`,
        )
        .get(r.id) as { c: number }
    ).c;
    return {
      ...r,
      plan: planRow
        ? {
            id: planRow.id,
            difficulty: planRow.difficulty,
            status: planRow.status,
          }
        : null,
      attemptCount,
    };
  });
}

export async function getDocument(id: number) {
  const row = db
    .prepare(`SELECT * FROM documents WHERE id = ?`)
    .get(id) as DocumentRow | undefined;
  if (!row) return null;
  return {
    id: row.id,
    filename: row.filename,
    title: row.title,
    status: row.status,
    markdown_chars: row.markdown_chars,
    created_at: row.created_at,
    error: row.error,
  };
}

export async function getDocumentMarkdown(id: number): Promise<string | null> {
  const row = db
    .prepare(`SELECT markdown FROM documents WHERE id = ?`)
    .get(id) as { markdown: string | null } | undefined;
  return row?.markdown ?? null;
}

export async function uploadAndConvert(
  filename: string,
  buffer: Buffer,
): Promise<DocumentRow> {
  const storedFilename = `${Date.now()}-${nanoid(8)}-${filename.replace(/[^a-zA-Z0-9.\-_ ]/g, "")}`;
  const filepath = path.join(UPLOADS_DIR, storedFilename);
  const { writeFile } = await import("node:fs/promises");
  await writeFile(filepath, buffer);

  const doc = db
    .prepare(
      `INSERT INTO documents (filename, stored_filename, filepath, status)
       VALUES (?, ?, ?, 'processing')
       RETURNING *`,
    )
    .get(filename, storedFilename, filepath) as DocumentRow;

  convertPdfToMarkdown(filepath)
    .then(async (result) => {
      if (!result.ok) {
        db.prepare(
          `UPDATE documents SET status = 'failed', error = ? WHERE id = ?`,
        ).run(result.error ?? "Unknown error", doc.id);
        return;
      }
      db.prepare(
        `UPDATE documents SET status = 'ready', markdown = ?, markdown_chars = ?, error = NULL WHERE id = ?`,
      ).run(result.markdown, result.markdown.length, doc.id);
    })
    .catch((err: unknown) => {
      db.prepare(
        `UPDATE documents SET status = 'failed', error = ? WHERE id = ?`,
      ).run((err as Error).message, doc.id);
    });

  return doc;
}

export async function createPlan(documentId: number) {
  const doc = db
    .prepare(`SELECT * FROM documents WHERE id = ?`)
    .get(documentId) as DocumentRow | undefined;
  if (!doc) throw new Error("Document not found");
  if (doc.status !== "ready" || !doc.markdown) {
    throw new Error(
      `Document is not ready for plan generation (status: ${doc.status})`,
    );
  }

  const plan = await generatePlan(doc.markdown, doc.filename);
  const objectivesJson = JSON.stringify(plan.objectives);
  const res = db
    .prepare(
      `INSERT INTO lesson_plans (document_id, title, description, objectives, difficulty, status)
       VALUES (?, ?, ?, ?, ?, 'draft')
       RETURNING *`,
    )
    .get(
      documentId,
      plan.title,
      plan.description,
      objectivesJson,
      plan.difficulty,
    ) as LessonPlanRow;

  return {
    id: res.id,
    document_id: documentId,
    title: res.title,
    description: res.description,
    difficulty: res.difficulty as
      | "beginner"
      | "intermediate"
      | "advanced",
    objectives: plan.objectives,
    status: res.status as "draft" | "approved" | "completed",
    created_at: res.created_at,
  };
}

export async function getPlan(planId: number) {
  const row = db
    .prepare(`SELECT * FROM lesson_plans WHERE id = ?`)
    .get(planId) as LessonPlanRow | undefined;
  if (!row) return null;
  const doc = db
    .prepare(`SELECT filename FROM documents WHERE id = ?`)
    .get(row.document_id) as { filename: string };
  return {
    id: row.id,
    document_id: row.document_id,
    document_filename: doc.filename,
    title: row.title,
    description: row.description,
    difficulty: row.difficulty as "beginner" | "intermediate" | "advanced",
    objectives: JSON.parse(row.objectives) as Objective[],
    status: row.status as "draft" | "approved" | "completed",
    created_at: row.created_at,
  };
}

export async function getPlansForDocument(documentId: number) {
  const rows = db
    .prepare(
      `SELECT * FROM lesson_plans WHERE document_id = ? ORDER BY datetime(created_at) DESC`,
    )
    .all(documentId) as LessonPlanRow[];
  return rows.map((row) => ({
    id: row.id,
    document_id: row.document_id,
    title: row.title,
    description: row.description,
    difficulty: row.difficulty as "beginner" | "intermediate" | "advanced",
    objectives: JSON.parse(row.objectives) as Objective[],
    status: row.status as "draft" | "approved" | "completed",
    created_at: row.created_at,
  }));
}

export async function approvePlan(planId: number) {
  const row = db
    .prepare(`SELECT * FROM lesson_plans WHERE id = ?`)
    .get(planId) as LessonPlanRow | undefined;
  if (!row) throw new Error("Plan not found");
  if (row.status === "draft") {
    db.prepare(`UPDATE lesson_plans SET status = 'approved' WHERE id = ?`).run(
      planId,
    );
  }
  return getPlan(planId);
}

export async function getOrCreateQuiz(
  planId: number,
  objectiveIndex: number,
): Promise<QuizDTO> {
  const plan = await getPlan(planId);
  if (!plan) throw new Error("Plan not found");
  const objective = plan.objectives[objectiveIndex];
  if (!objective)
    throw new Error(`Objective ${objectiveIndex} not found`);

  const existing = db
    .prepare(
      `SELECT * FROM quiz_questions WHERE lesson_plan_id = ? AND objective_index = ?`,
    )
    .get(planId, objectiveIndex) as QuizQuestionRow | undefined;

  if (existing) {
    return {
      id: existing.id,
      objectiveIndex: existing.objective_index,
      objectiveText: existing.objective_text,
      question: existing.question,
      options: JSON.parse(existing.options),
      hint: existing.hint,
    };
  }

  const markdown = await getDocumentMarkdown(plan.document_id);
  if (!markdown) throw new Error("Source document has no markdown content");
  const quiz = await generateQuiz(
    markdown,
    objective.text,
    objective.topic,
  );

  const res = db
    .prepare(
      `INSERT INTO quiz_questions (lesson_plan_id, objective_index, objective_text, question, options, correct_index, explanation, hint)
       VALUES (?, ?, ?, ?, ?, ?, ?, ?)
       RETURNING id`,
    )
    .get(
      planId,
      objectiveIndex,
      objective.text,
      quiz.question,
      JSON.stringify(quiz.options),
      quiz.correct_index,
      quiz.explanation,
      quiz.hint,
    ) as { id: number };

  return {
    id: res.id,
    objectiveIndex,
    objectiveText: objective.text,
    question: quiz.question,
    options: quiz.options,
    hint: quiz.hint,
  };
}

export async function getAllQuizzes(planId: number): Promise<QuizDTO[]> {
  const plan = await getPlan(planId);
  if (!plan) return [];
  const rows = db
    .prepare(
      `SELECT * FROM quiz_questions WHERE lesson_plan_id = ? ORDER BY objective_index ASC`,
    )
    .all(planId) as QuizQuestionRow[];
  return rows.map((r) => ({
    id: r.id,
    objectiveIndex: r.objective_index,
    objectiveText: r.objective_text,
    question: r.question,
    options: JSON.parse(r.options),
    hint: r.hint,
  }));
}

export async function getQuizInternal(
  quizId: number,
): Promise<QuizQuestionRow | null> {
  return (
    (db
      .prepare(`SELECT * FROM quiz_questions WHERE id = ?`)
      .get(quizId) as QuizQuestionRow | undefined) ?? null
  );
}

export async function getHint(
  quizId: number,
  previousGuessIndex: number | null,
): Promise<string> {
  const quiz = await getQuizInternal(quizId);
  if (!quiz) throw new Error("Quiz not found");
  const plan = await getPlan(quiz.lesson_plan_id);
  if (!plan) throw new Error("Plan not found");
  const markdown = await getDocumentMarkdown(plan.document_id);
  if (!markdown) throw new Error("Source document has no markdown content");
  const options = JSON.parse(quiz.options) as string[];
  return generateRetryHint(
    markdown,
    quiz.question,
    options,
    previousGuessIndex !== null ? options[previousGuessIndex] : null,
  );
}

export async function getExplanation(quizId: number): Promise<{
  explanation: string;
  correctIndex: number;
}> {
  const quiz = await getQuizInternal(quizId);
  if (!quiz) throw new Error("Quiz not found");
  const plan = await getPlan(quiz.lesson_plan_id);
  if (!plan) throw new Error("Plan not found");
  const markdown = await getDocumentMarkdown(plan.document_id);
  if (!markdown) throw new Error("Source document has no markdown content");
  const options = JSON.parse(quiz.options) as string[];
  const correct = options[quiz.correct_index];
  const explanation = await explainCorrect(
    markdown,
    quiz.question,
    options,
    correct,
    quiz.correct_index,
  );
  return { explanation, correctIndex: quiz.correct_index };
}

export async function checkAnswer(
  quizId: number,
  learnerIndex: number,
): Promise<{ correct: boolean; explanation?: string }> {
  const quiz = await getQuizInternal(quizId);
  if (!quiz) throw new Error("Quiz not found");
  const correct = learnerIndex === quiz.correct_index;
  if (!correct) return { correct: false };
  const { explanation } = await getExplanation(quizId);
  return { correct: true, explanation };
}

export async function learnMoreAboutQuiz(
  quizId: number,
  learnerQuestion: string,
  history: Array<{ role: "user" | "assistant"; content: string }>,
): Promise<string> {
  const quiz = await getQuizInternal(quizId);
  if (!quiz) throw new Error("Quiz not found");
  const plan = await getPlan(quiz.lesson_plan_id);
  if (!plan) throw new Error("Plan not found");
  const markdown = await getDocumentMarkdown(plan.document_id);
  if (!markdown) throw new Error("Source document has no markdown content");
  const options = JSON.parse(quiz.options) as string[];
  return learnMore(markdown, quiz.question, options, learnerQuestion, history);
}

export async function completeAttempt(
  planId: number,
  payload: {
    answers: Array<{
      quizId: number;
      learnerIndex: number | null;
      attempts: number;
    }>;
  },
): Promise<AttemptSummaryDTO> {
  const plan = await getPlan(planId);
  if (!plan) throw new Error("Plan not found");

  const markdown = await getDocumentMarkdown(plan.document_id);
  if (!markdown) throw new Error("Source document has no markdown content");

  const questions: AttemptInput["questions"] = [];
  let score = 0;
  for (const ans of payload.answers) {
    const quiz = await getQuizInternal(ans.quizId);
    if (!quiz || quiz.lesson_plan_id !== planId) continue;
    const options = JSON.parse(quiz.options) as string[];
    const correct =
      ans.learnerIndex === quiz.correct_index;
    if (correct) score += 1;
    questions.push({
      objectiveText: quiz.objective_text,
      question: quiz.question,
      options,
      correctIndex: quiz.correct_index,
      learnerIndex: ans.learnerIndex,
      attempts: ans.attempts,
    });
  }

  const summary = await generateSummary({
    objectives: plan.objectives.map((o) => ({
      text: o.text,
      topic: o.topic,
    })),
    questions,
    markdown,
  });

  db.prepare(
    `INSERT INTO attempts (lesson_plan_id, score, total, answers, summary, study_tips)
     VALUES (?, ?, ?, ?, ?, ?)
     RETURNING id`,
  ).get(
    planId,
    score,
    questions.length,
    JSON.stringify(payload.answers),
    summary.summary,
    JSON.stringify(summary.study_tips),
  ) as { id: number };

  db.prepare(`UPDATE lesson_plans SET status = 'completed' WHERE id = ?`).run(
    planId,
  );

  return {
    score,
    total: questions.length,
    summary: summary.summary,
    studyTips: summary.study_tips,
    weakTopics: summary.weak_topics,
    strengths: summary.strengths,
    answers: questions.map((q) => ({
      question: q.question,
      options: q.options,
      correctIndex: q.correctIndex,
      learnerIndex: q.learnerIndex,
      attempts: q.attempts,
      objectiveText: q.objectiveText,
    })),
  };
}

export async function listAttempts(planId: number) {
  const rows = db
    .prepare(
      `SELECT * FROM attempts WHERE lesson_plan_id = ? ORDER BY datetime(created_at) DESC`,
    )
    .all(planId) as AttemptRow[];
  return rows.map((r) => ({
    id: r.id,
    lesson_plan_id: r.lesson_plan_id,
    score: r.score,
    total: r.total,
    summary: r.summary,
    study_tips: JSON.parse(r.study_tips) as string[],
    created_at: r.created_at,
  }));
}

export async function getAttempt(attemptId: number) {
  const row = db
    .prepare(`SELECT * FROM attempts WHERE id = ?`)
    .get(attemptId) as AttemptRow | undefined;
  if (!row) return null;
  return {
    id: row.id,
    lesson_plan_id: row.lesson_plan_id,
    score: row.score,
    total: row.total,
    summary: row.summary,
    study_tips: JSON.parse(row.study_tips) as string[],
    created_at: row.created_at,
  };
}

