    const body = (req.body ?? {}) as { previousGuessIndex?: number | null };
    try {
      const hint = await svc.getHint(
        id,
        body.previousGuessIndex ?? null,
      );
      return { hint };
    } catch (err) {
      return reply
        .code(400)
        .send({ error: (err as Error).message });
    }
  });

  app.post("/api/quizzes/:id/learn-more", async (req, reply) => {
    const id = Number((req.params as { id: string }).id);
    const body = req.body as {
      learnerQuestion?: string;
      history?: Array<{
        role: "user" | "assistant";
        content: string;
      }>;
    };
    if (!body?.learnerQuestion) {
      return reply
        .code(400)
        .send({ error: "learnerQuestion is required" });
    }
    try {
      const message = await svc.learnMoreAboutQuiz(
        id,
        body.learnerQuestion,
        body.history ?? [],
      );
      return { message };
    } catch (err) {
      return reply
        .code(400)
        .send({ error: (err as Error).message });
    }
  });

  app.post("/api/lesson-plans/:id/complete", async (req, reply) => {
    const id = Number((req.params as { id: string }).id);
    const body = req.body as {
      answers?: Array<{
        quizId: number;
        learnerIndex: number | null;
        attempts: number;
      }>;
    };
    if (!body?.answers) {
      return reply
        .code(400)
        .send({ error: "answers is required" });
    }
    try {
      return await svc.completeAttempt(id, { answers: body.answers });
    } catch (err) {
      return reply
        .code(400)
        .send({ error: (err as Error).message });
    }
  });

  app.get("/api/lesson-plans/:id/attempts", async (req) => {
    const id = Number((req.params as { id: string }).id);
    return svc.listAttempts(id);
  });

  app.get("/api/attempts/:id", async (req, reply) => {
    const id = Number((req.params as { id: string }).id);
    const attempt = await svc.getAttempt(id);
    if (!attempt)
      return reply.code(404).send({ error: "Attempt not found" });
    return attempt;
  });
}

