display.text:
import { spawn } from "node:child_process";
import path from "node:path";
import { PDF_CONVERTER_PYTHON, PDF_CONVERTER_SCRIPT } from "../config.ts";

export interface ConvertResult {
  ok: boolean;
  markdown: string;
  error?: string;
}

export function convertPdfToMarkdown(
  inputPath: string,
): Promise<ConvertResult> {
  return new Promise((resolve) => {
    const outputPath = path.join(
      path.dirname(inputPath),
      `${path.basename(inputPath, ".pdf")}.md`,
    );

    const proc = spawn(PDF_CONVERTER_PYTHON, [
      PDF_CONVERTER_SCRIPT,
      "--input",
      inputPath,
      "--output",
      outputPath,
    ]);

    let stderr = "";
    proc.stderr.on("data", (chunk: Buffer) => {
      stderr += chunk.toString();
    });

    let stdout = "";
    proc.stdout.on("data", (chunk: Buffer) => {
      stdout += chunk.toString();
    });

    proc.on("error", (err) => {
      resolve({
        ok: false,
        markdown: "",
        error: `Failed to spawn converter: ${err.message}`,
      });
    });

    proc.on("close", async (code) => {
      if (code !== 0) {
        resolve({
          ok: false,
          markdown: "",
          error: `Converter exited with code ${code}. ${stderr}`.trim(),
        });
        return;
      }
      try {
        const { readFile } = await import("node:fs/promises");
        const markdown = await readFile(outputPath, "utf-8");
        if (!markdown.trim()) {
          resolve({
            ok: false,
            markdown: "",
            error: "Converter produced empty output.",
          });
          return;
        }
        resolve({ ok: true, markdown });
      } catch (err) {
        resolve({
          ok: false,
          markdown: "",
          error: `Failed to read output: ${(err as Error).message}`,
        });
      }
    });
  });
}

